import fs from "node:fs";
import path from "node:path";

function nowIso() {
  return new Date().toISOString();
}

function ensureDir(p) {
  fs.mkdirSync(p, { recursive: true });
}

function parseStepStatus(text) {
  // run-all.sh prints: "=== RESULT: <name>: PASS|FAIL|SKIP ..."
  const lines = String(text || "").split("\n");
  const steps = [];
  for (const line of lines) {
    const m = line.match(/^=== RESULT:\s*(.+?)\s*:\s*(PASS|FAIL|SKIP)\b/);
    if (m) steps.push({ name: m[1], status: m[2] });
  }
  return steps;
}

function buildReport({ baseUrl, stdout, exitCode }) {
  const steps = parseStepStatus(stdout);
  const failed = steps.filter((s) => s.status === "FAIL").map((s) => s.name);
  const skipped = steps.filter((s) => s.status === "SKIP").map((s) => s.name);

  return {
    run_id: nowIso(),
    base_url: baseUrl || null,
    exit_code: exitCode,
    steps,
    failed_steps: failed,
    skipped_steps: skipped,
    artifacts: {
      playwright_output_dir: "test-results/",
      lighthouse_dir: "artifacts/lighthouse/",
      linkcheck_dir: "artifacts/linkcheck/"
    },
    notes: [
      "This report is generated from verify:all console summary lines.",
      "If you change run-all.sh RESULT format, update parser in scripts/verify/verify-report.mjs."
    ]
  };
}

function main() {
  const baseUrl = process.env.BASE_URL || process.env.baseURL || "";
  const outPath =
    process.argv[2] || path.join(process.cwd(), "artifacts", "verify", "verify-report.json");

  let stdout = "";
  try {
    stdout = fs.readFileSync(0, "utf8");
  } catch {
    stdout = "";
  }

  const exitCode = Number(process.env.VERIFY_ALL_EXIT_CODE || 0);
  const report = buildReport({ baseUrl, stdout, exitCode });

  ensureDir(path.dirname(outPath));
  fs.writeFileSync(outPath, JSON.stringify(report, null, 2) + "\n", "utf8");
  process.stdout.write(JSON.stringify({ wrote: outPath }) + "\n");
}

