import { spawnSync } from "node:child_process";

function usage() {
  // eslint-disable-next-line no-console
  console.error(
    "Usage: node scripts/verify/playwright-assert.mjs <spec...> [-- <extra playwright args...>]\n" +
      "Fails if Playwright reports any skipped tests unless ALLOW_SKIPS=1."
  );
}

function toInt(v, fallback = 0) {
  const n = Number(v);
  return Number.isFinite(n) ? n : fallback;
}

function extractJson(text) {
  const s = String(text || "").trim();
  if (!s) return null;

  // Playwright json reporter prints a single JSON object. Be defensive:
  // take the last '{' and try parse from there.
  const idx = s.lastIndexOf("{");
  if (idx < 0) return null;
  const candidate = s.slice(idx);
  try {
    return JSON.parse(candidate);
  } catch {
    return null;
  }
}

function main() {
  const args = process.argv.slice(2);
  if (args.length === 0) {
    usage();
    process.exit(2);
  }

  const splitIdx = args.indexOf("--");
  const specArgs = splitIdx >= 0 ? args.slice(0, splitIdx) : args;
  const extraArgs = splitIdx >= 0 ? args.slice(splitIdx + 1) : [];

  if (specArgs.length === 0) {
    usage();
    process.exit(2);
  }

  const allowSkips = String(process.env.ALLOW_SKIPS || "0") === "1";

  const cmd = process.platform === "win32" ? "npx.cmd" : "npx";
  const pwArgs = [
    "playwright",
    "test",
    ...specArgs,
    "--reporter=json",
    ...extraArgs,
  ];

  const res = spawnSync(cmd, pwArgs, {
    encoding: "utf8",
    stdio: ["inherit", "pipe", "inherit"],
    env: process.env,
  });

  // Always forward JSON to stdout, but keep it in a variable for parsing.
  const stdout = res.stdout || "";
  process.stdout.write(stdout);

  if (res.status !== 0) {
    process.exit(res.status ?? 1);
  }

  const json = extractJson(stdout);
  const stats = json?.stats || json?.metadata?.stats || null;
  const skipped = toInt(stats?.skipped, 0);

  if (!allowSkips && skipped > 0) {
    // eslint-disable-next-line no-console
    console.error(`ERROR: Playwright reported skipped tests (${skipped}). Failing (set ALLOW_SKIPS=1 to override).`);
    process.exit(1);
  }

  process.exit(0);
}

